import React from 'react';
import { useCart } from '../contexts/CartContext';
import GlassCard from '../components/GlassCard';

/**
 * Products page with cart functionality
 * Will be enhanced in later tasks with actual product functionality
 */
const Products = () => {
  const { addToCart, isInCart, getItemQuantity } = useCart();

  // Demo products for testing cart functionality
  const demoProducts = [
    { id: 1, name: 'Vitamin D3 Supplement', category: 'Supplement', price: 15.99, stock: 50 },
    { id: 2, name: 'Pain Relief Tablets', category: 'Medication', price: 8.50, stock: 25 },
    { id: 3, name: 'Hand Sanitizer', category: 'Personal Care', price: 4.99, stock: 100 },
    { id: 4, name: 'Omega-3 Fish Oil', category: 'Supplement', price: 22.75, stock: 30 },
    { id: 5, name: 'First Aid Kit', category: 'Medical Supplies', price: 35.00, stock: 15 },
    { id: 6, name: 'Multivitamin Complex', category: 'Supplement', price: 18.99, stock: 40 }
  ];

  const handleAddToCart = (product) => {
    const success = addToCart(product, 1);
    if (success) {
      // In a real app, you might show a toast notification here
      console.log(`Added ${product.name} to cart`);
    }
  };

  return (
    <div className="pt-24 pb-16">
      <div className="max-w-6xl mx-auto px-4">
        <GlassCard className="p-8 text-center mb-8">
          <h1 className="text-gray-800 mb-4">Our Products</h1>
          <p className="text-gray-600">
            Browse our comprehensive selection of medications, supplements, and healthcare products.
          </p>
        </GlassCard>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {demoProducts.map((product) => {
            const inCart = isInCart(product.id);
            const quantity = getItemQuantity(product.id);
            
            return (
              <GlassCard key={product.id} className="p-6" hover>
                <div className="aspect-square bg-gradient-to-br from-glass-blue/20 to-glass-green/20 rounded-lg mb-4 flex items-center justify-center">
                  <span className="text-gray-500">Product Image</span>
                </div>
                
                <div className="mb-4">
                  <h3 className="text-gray-800 mb-2 font-semibold">{product.name}</h3>
                  <p className="text-sm text-gray-500 mb-2">{product.category}</p>
                  <p className="text-gray-600 mb-3">
                    High-quality {product.category.toLowerCase()} for your health needs.
                  </p>
                  <p className="text-sm text-gray-500">
                    Stock: {product.stock} available
                  </p>
                </div>
                
                <div className="flex justify-between items-center">
                  <span className="text-lg font-semibold text-gray-800">
                    ${product.price.toFixed(2)}
                  </span>
                  
                  <div className="flex items-center space-x-2">
                    {inCart && (
                      <span className="text-sm text-green-600 font-medium">
                        In cart ({quantity})
                      </span>
                    )}
                    <button
                      onClick={() => handleAddToCart(product)}
                      className="glass-button-primary"
                      disabled={product.stock === 0}
                    >
                      {product.stock === 0 ? 'Out of Stock' : 'Add to Cart'}
                    </button>
                  </div>
                </div>
              </GlassCard>
            );
          })}
        </div>
        
        {/* Demo Instructions */}
        <GlassCard className="p-6 mt-8">
          <h2 className="text-gray-800 mb-4">Demo Instructions</h2>
          <div className="text-gray-600 space-y-2">
            <p>• Click "Add to Cart" on any product to test the cart functionality</p>
            <p>• Check the cart icon in the header to see the item count update</p>
            <p>• Visit the Shopping Cart page to manage your items</p>
            <p>• Cart data is automatically saved to localStorage</p>
          </div>
        </GlassCard>
      </div>
    </div>
  );
};

export default Products;
